export const About = () => {
	return (
		<div className="about">
			<div className="about-content">
				<h1>What is SpotifyMe?</h1>
                <p>
                    SpotifyMe was inspired by that one thing we all wait for towards the end of the year, <strong>Spotify Wrapped</strong>! 
                    Aren't we curious as to how our music tastes and genre changes through the weeks, months, and even throughout the years? 
                    I know I am. I wanted to make this web application as simple to use as possible, so for now, you are able to do the 
                    following: select which time frames you would like to view which artists and tracks you've listened to, and based on 
                    the current time frame of the tracks you've selected, there will be songs recommended to you. You can determine if you like
                    the recommended song by pressing the <code><i>Play Song</i></code> button, and if you do, you can add it to any of your owned playlists by 
                    pressing the <code><i>Add Song</i></code> button. If you have any questions, comments, or suggestions for this application, please head over
                    to the <a href="/feedback">askdjn</a>
                </p>
			</div>
		</div>
	);
};
